import openpyxl

def verify(workspace_path, external_services_path=None):
    xlsx_path = Path(workspace_path) / 'expense_reports.xlsx'
    if not xlsx_path.exists():
        return {'pass': False, 'score': 0.0, 'feedback': 'expense_reports.xlsx not found'}
    try:
        wb = openpyxl.load_workbook(xlsx_path)
    except Exception as e:
        return {'pass': False, 'score': 0.0, 'feedback': f'Failed to open file: {e}'}
    required_headers = ['Jira Key', 'Date of Purchase', 'Merchant', 'Amount', 'Expense Category', 'Approved Amount', 'Denied Amount', 'Denial Reason']
    sheets_to_check = ['Amina Hassan', 'Leila Rahimi', 'Hiroshi Tanaka', 'Carlos Mendez', 'Priya Natarajan']
    failures = []
    for sheet_name in sheets_to_check:
        if sheet_name not in wb.sheetnames:
            failures.append(f'Sheet "{sheet_name}" not found')
            continue
        ws = wb[sheet_name]
        actual_headers = [str(ws.cell(row=1, column=i).value or '').strip() for i in range(1, 9)]
        for i, (expected, actual) in enumerate(zip(required_headers, actual_headers), 1):
            if expected.lower() != actual.lower():
                failures.append(f'Sheet "{sheet_name}" col {i}: expected "{expected}", got "{actual}"')
