from pathlib import Path
import openpyxl
import re
import datetime

def normalize_str(s):
    return str(s or '').strip().lower()

def parse_amount(val):
    if val is None:
        return None
    s = str(val).replace('$', '').replace(',', '').strip()
    try:
        return float(s)
    except:
        return None

def parse_date_tuple(val):
    """Return (month, day, year) tuple, or None if unparseable."""
    if val is None:
        return None
    if isinstance(val, (datetime.datetime, datetime.date)):
        return (val.month, val.day, val.year)
    s = str(val).strip()
    # M/D/YYYY or MM/DD/YYYY
    m = re.match(r'(\d{1,2})/(\d{1,2})/(\d{4})', s)
    if m:
        return (int(m.group(1)), int(m.group(2)), int(m.group(3)))
    # YYYY-MM-DD
    m = re.match(r'(\d{4})-(\d{1,2})-(\d{1,2})', s)
    if m:
        return (int(m.group(2)), int(m.group(3)), int(m.group(1)))
    return None

def date_matches(actual_cell, expected_str):
    """Flexible date comparison. Handles datetime objects, M/D/YYYY, YYYY-MM-DD,
    and range strings like '5/5/2026 - 5/8/2026'."""
    exp_lower = expected_str.lower().strip()
    # Range case: accept if actual text contains the range, or actual parses
    # to either the start or end date of the range.
    if '-' in exp_lower and '/' in exp_lower:
        parts = re.findall(r'(\d{1,2})/(\d{1,2})/(\d{4})', exp_lower)
        if len(parts) >= 2:
            start = (int(parts[0][0]), int(parts[0][1]), int(parts[0][2]))
            end = (int(parts[1][0]), int(parts[1][1]), int(parts[1][2]))
            act_str = normalize_str(actual_cell)
            # Accept a textual range that mentions both dates
            if all(f"{m}/{d}" in act_str or f"{m:02d}/{d:02d}" in act_str
                   for m, d, _ in (start, end)):
                return True
            act_tuple = parse_date_tuple(actual_cell)
            if act_tuple in (start, end):
                return True
            return False
    # Single date case
    exp_tuple = parse_date_tuple(expected_str)
    act_tuple = parse_date_tuple(actual_cell)
    if exp_tuple and act_tuple and exp_tuple == act_tuple:
        return True
    # Fallback: substring match on normalized strings
    act_str = normalize_str(actual_cell)
    if exp_lower in act_str or act_str in exp_lower:
        return True
    return False

