    if 'ops-hr-te-rahimi-2026-05-11' not in jk:
        failures.append(f'Jira Key expected OPS-57, got "{summary.get("jira key", "")}"')
    ta = parse_amount(summary.get('total approved'))
    if ta is None or abs(ta - 2966.61) > 1.50:
        failures.append(f'Total Approved expected 2966.61 (±1.50), got {summary.get("total approved")}')
    td = parse_amount(summary.get('total denied'))
    if td is None:
        td = 0.0
    if abs(td - 115.73) > 1.50:
        failures.append(f'Total Denied expected 115.73 (±1.50), got {summary.get("total denied")}')
    fs = normalize_str(summary.get('final status', ''))
    if 'partial' not in fs:
        failures.append(f'Final Status expected "Partially Approved", got "{summary.get("final status", "")}"')
    mn = normalize_str(summary.get('manager notified', ''))
    if 'n' not in mn:
        failures.append(f'Manager Notified expected "N", got "{summary.get("manager notified", "")}"')
    comment_key = None
    for k in summary:
        if 'comment' in k:
            comment_key = k
            break
    if comment_key is None:
        failures.append('No Comment/Comments label found in summary')
    else:
        comment_val = normalize_str(summary[comment_key])
        expected_comment = 't&e review complete. expenses approved except where noted.'
        if expected_comment not in comment_val and comment_val not in expected_comment:
            failures.append(f'Comment expected "T&E review complete. Expenses approved except where noted.", got "{summary[comment_key]}"')
    if failures:
