from pathlib import Path
import json
import re
from datetime import datetime

def verify(workspace_path, external_services_path=None):
    """
    Verify rubric item 6: Hiroshi Tanaka worksheet line items in expense_reports.xlsx
    """
    feedback_parts = []
    total_checks = 0
    passed_checks = 0

    # Find the xlsx file
    ws = Path(workspace_path)
    xlsx_files = list(ws.glob('**/expense_reports.xlsx'))
    if not xlsx_files:
        xlsx_files = list(ws.glob('**/*.xlsx'))
    if not xlsx_files:
        return {'pass': False, 'score': 0.0, 'feedback': 'No xlsx file found in workspace'}

    xlsx_path = xlsx_files[0]

    try:
        import openpyxl
        wb = openpyxl.load_workbook(str(xlsx_path), data_only=True)
    except Exception as e:
        return {'pass': False, 'score': 0.0, 'feedback': f'Failed to open {xlsx_path.name}: {e}'}

    # Find the Hiroshi Tanaka worksheet
    target_sheet = None
    for name in wb.sheetnames:
        if 'tanaka' in name.lower() and 'hiroshi' in name.lower():
            target_sheet = wb[name]
            break
    if target_sheet is None:
        for name in wb.sheetnames:
            if 'tanaka' in name.lower():
                target_sheet = wb[name]
                break
    if target_sheet is None:
        return {'pass': False, 'score': 0.0, 'feedback': f'No worksheet found for Hiroshi Tanaka. Sheets: {wb.sheetnames}'}

    feedback_parts.append(f'Found worksheet: "{target_sheet.title}"')

    # Read all rows into a dict keyed by Jira Key (column A)
    rows_by_key = {}
    for row in target_sheet.iter_rows(min_row=1, max_col=8, values_only=False):
        cell_a = row[0].value
        if cell_a is None:
            continue
        key_str = str(cell_a).strip()
        if key_str.startswith('OPS-HR-TE-Tanaka'):
            row_vals = [c.value for c in row]
            rows_by_key[key_str] = row_vals

    def parse_amount(val):
        """Parse a dollar amount from various formats, return float or None."""
        if val is None:
            return None
        if isinstance(val, (int, float)):
            return float(val)
        s = str(val).strip()
        # Remove $, commas
        s = s.replace('$', '').replace(',', '').strip()
        try:
            return float(s)
        except ValueError:
            return None

    def parse_date(val):
        """Normalize date to a comparable string. Return lowercased string."""
        if val is None:
            return ''
        if isinstance(val, datetime):
            return val.strftime('%-m/%-d/%Y').replace('/0', '/').lstrip('0') if False else val.strftime('%m/%d/%Y').lstrip('0').replace('/0', '/')
        s = str(val).strip()
        return s

    def dates_match(actual, expected):
        """Loosely compare dates."""
        if actual is None:
            return False
        # Normalize both
        def norm(d):
            if isinstance(d, datetime):
                return d.strftime('%Y-%m-%d')
            s = str(d).strip()
            # Try multiple parsing
            for fmt in ['%m/%d/%Y', '%Y-%m-%d', '%m/%d/%y', '%d/%m/%Y']:
                try:
                    return datetime.strptime(s, fmt).strftime('%Y-%m-%d')
                except ValueError:
                    continue
            return s.lower()
        # For date ranges like "5/5/2026 - 5/9/2026"
        if '-' in str(expected) and '/' in str(expected):
            # It's a range; just check containment loosely
            act_str = str(actual).replace(' ', '').lower()
            exp_str = str(expected).replace(' ', '').lower()
            # Normalize slashes
            def norm_date_str(s):
                # Remove leading zeros
                return re.sub(r'\b0+(\d)', r'\1', s)
            return norm_date_str(act_str) == norm_date_str(exp_str) or \
                   norm_date_str(exp_str) in norm_date_str(act_str) or \
                   norm_date_str(act_str) in norm_date_str(exp_str) or \
                   (norm(str(expected).split('-')[0].strip()) in norm(actual) if isinstance(actual, str) else False)
        return norm(actual) == norm(expected)

    def merchant_matches(actual, expected):
        if actual is None:
            return False
        a = str(actual).strip().lower()
        e = expected.strip().lower()
        # Fuzzy: check containment or near match
        if a == e:
            return True
        if e in a or a in e:
            return True
        # Remove punctuation
        def depunct(s):
            return re.sub(r'[^a-z0-9 ]', '', s)
        return depunct(a) == depunct(e)

    def category_matches(actual, expected):
        if actual is None:
            return False
        a = str(actual).strip().lower()
        e = expected.strip().lower()
        return a == e or e in a or a in e

    def amount_close(actual, expected, tol=0.05):
        a = parse_amount(actual)
        if a is None:
            return False
        return abs(a - expected) <= tol

    def denied_is_zero(val):
        if val is None or str(val).strip() == '':
            return True
        a = parse_amount(val)
        if a is None:
            return True  # empty/non-numeric is fine
        return abs(a) < 0.01

    def denial_reason_empty(val):
        if val is None:
            return True
        s = str(val).strip()
        return s == '' or s.lower() == 'none' or s == '0'

    def is_mileage_amount(val, expected_miles):
        """Check if the amount cell is either the mileage string or the dollar equivalent."""
        if val is None:
            return False
        s = str(val).strip().lower()
        # Check for mileage string
        if str(expected_miles) in s and 'mile' in s:
            return True
        # Check for dollar equivalent
        dollar = expected_miles * 0.725
        a = parse_amount(val)
        if a is not None and abs(a - dollar) < 0.10:
            return True
        if a is not None and abs(a - expected_miles) < 0.10:
            return True
        return False

    # Define expected rows
    # Format: (jira_key, date, merchant, amount_or_miles, is_mileage, miles_count, category, approved_amount, approved_tol, denied_zero)
    expected_rows = [
        ('OPS-59', '5/5/2026', 'Self drove (mileage)', None, True, 357, 'Staff Expense', 258.83, 0.05),
        ('OPS-58', '5/5/2026', 'Sable & Oak Kitchen', 38.59, False, 0, 'Staff Expense', 38.59, 0.05),
        ('OPS-60', '5/6/2026', 'Gloriana Bakery', 9.10, False, 0, 'Staff Expense', 9.10, 0.05),
        ('OPS-61', '5/6/2026', 'Wicker Park Kitchen', 21.22, False, 0, 'Staff Expense', 21.22, 0.05),
        ('OPS-62', '5/6/2026', 'Harbor Light Bistro', 45.20, False, 0, 'Staff Expense', 45.20, 0.05),
        ('OPS-63', '5/7/2026', 'Gloriana Bakery', 10.47, False, 0, 'Staff Expense', 10.47, 0.05),
        ('OPS-64', '5/7/2026', 'Bucktown Bites', 26.40, False, 0, 'Staff Expense', 26.40, 0.05),
        ('OPS-65', '5/7/2026', 'Mariscos Del Lago', 33.07, False, 0, 'Staff Expense', 33.07, 0.05),
        ('OPS-66', '5/8/2026', 'Gloriana Bakery', 11.02, False, 0, 'Staff Expense', 11.02, 0.05),
        ('OPS-67', '5/8/2026', 'Lincoln Square Cafe', 26.13, False, 0, 'Staff Expense', 26.13, 0.05),
        ('OPS-68', '5/9/2026', 'Gloriana Bakery', 11.85, False, 0, 'Staff Expense', 11.85, 0.05),
        ('OPS-69', '5/9/2026', 'Loop Street Deli', 25.63, False, 0, 'Staff Expense', 25.63, 0.05),
        ('OPS-70', '5/9/2026', 'Koto Ramen & Izakaya', 39.69, False, 0, 'Staff Expense', 39.69, 0.05),
        ('OPS-71', '5/5/2026 - 5/9/2026', 'Hyatt Regency Chicago', 1916.99, False, 0, 'Staff Expense', 1916.99, 0.05),
        ('OPS-72', '5/10/2026', 'Gloriana Bakery', 11.30, False, 0, 'Staff Expense', 11.30, 0.05),
        ('OPS-73', '5/10/2026', 'Self drove (mileage)', None, True, 360, 'Staff Expense', 261.00, 0.05),
    ]

    for exp in expected_rows:
        jira_key, exp_date, exp_merchant, exp_amount, is_mileage, miles, exp_category, exp_approved, tol = exp
        total_checks += 1

        if jira_key not in rows_by_key:
            feedback_parts.append(f'FAIL: Row {jira_key} not found in worksheet')
            continue

        row = rows_by_key[jira_key]
        # Columns: A=JiraKey(0), B=Date(1), C=Merchant(2), D=Amount(3), E=Category(4), F=Approved(5), G=Denied(6), H=DenialReason(7)
        row_ok = True
        row_issues = []

        # Check Date (col B, index 1)
        if not dates_match(row[1], exp_date):
            row_ok = False
            row_issues.append(f'Date: expected "{exp_date}", got "{row[1]}"')

        # Check Merchant (col C, index 2)
        if not merchant_matches(row[2], exp_merchant):
            row_ok = False
            row_issues.append(f'Merchant: expected "{exp_merchant}", got "{row[2]}"')

        # Check Amount (col D, index 3)
        if is_mileage:
            if not is_mileage_amount(row[3], miles):
                row_ok = False
                row_issues.append(f'Amount: expected "{miles} miles" or ${miles*0.725:.2f}, got "{row[3]}"')
        else:
            if not amount_close(row[3], exp_amount, 0.05):
                row_ok = False
                row_issues.append(f'Amount: expected {exp_amount}, got "{row[3]}"')

        # Check Category (col E, index 4)
        if not category_matches(row[4], exp_category):
            row_ok = False
            row_issues.append(f'Category: expected "{exp_category}", got "{row[4]}"')

        # Check Approved Amount (col F, index 5)
        if not amount_close(row[5], exp_approved, tol):
            row_ok = False
            row_issues.append(f'Approved Amount: expected {exp_approved} (±{tol}), got "{row[5]}"')

        # Check Denied Amount (col G, index 6)
        denied_val = row[6] if len(row) > 6 else None
        if not denied_is_zero(denied_val):
