        else:
            feedback_parts.append(f'FAIL: Row {jira_key}: {"; ".join(row_issues)}')

    score = passed_checks / total_checks if total_checks > 0 else 0.0
    passed = score >= 0.8  # Allow some tolerance - pass if 80%+ rows correct

    feedback = f'Hiroshi Tanaka worksheet: {passed_checks}/{total_checks} rows correct (score={score:.2f}).\n' + '\n'.join(feedback_parts)
    return {'pass': passed, 'score': score, 'feedback': feedback}

from pathlib import Path
