            summary[key.lower()] = (key, b)

    feedback_parts = []
    checks_passed = 0
    total_checks = 6

    def clean_num(val):
        """Try to extract a numeric value from val."""
        if val is None:
            return None
        if isinstance(val, (int, float)):
            return float(val)
        s = str(val).strip()
        # Remove currency symbols, commas, spaces
        s = re.sub(r'[\$€£¥,\s]', '', s)
        try:
            return float(s)
        except ValueError:
            return None

    def find_label(possible_keys):
        """Find a summary entry matching any of the possible key strings (case-insensitive)."""
        for pk in possible_keys:
            pk_lower = pk.lower()
            for sk in summary:
                if pk_lower in sk or sk in pk_lower:
                    return summary[sk]
        return None

    # 1. Jira Key
    entry = find_label(["jira key", "jirakey", "jira"])
