            feedback_parts.append(f"FAIL: Total Approved expected ~2746.49 (±1.00), got '{val}' (parsed as {num})")
    else:
        feedback_parts.append("FAIL: No 'Total Approved' label found in Report Summary.")

    # 3. Total Denied = 0
    entry = find_label(["total denied", "totaldenied"])
