        orig_label, val = entry
        num = clean_num(val)
        if num is not None and abs(num - 0) <= 0.01:
            checks_passed += 1
            feedback_parts.append(f"PASS: Total Denied = {num}")
        else:
            # Also accept string "0" or blank/None as 0
            val_str = str(val).strip() if val is not None else ""
            if val_str in ["", "0", "0.0", "0.00", "$0", "$0.00"]:
                checks_passed += 1
                feedback_parts.append(f"PASS: Total Denied = '{val_str}' (treated as 0)")
            else:
                feedback_parts.append(f"FAIL: Total Denied expected 0, got '{val}' (parsed as {num})")
    else:
        feedback_parts.append("FAIL: No 'Total Denied' label found in Report Summary.")

    # 4. Final Status = Approved
    entry = find_label(["final status", "finalstatus", "status"])
    if entry:
        orig_label, val = entry
        val_str = str(val).strip() if val is not None else ""
        if val_str.lower() == "approved":
            checks_passed += 1
            feedback_parts.append(f"PASS: Final Status = '{val_str}'")
        else:
            feedback_parts.append(f"FAIL: Final Status expected 'Approved', got '{val_str}'")
    else:
        feedback_parts.append("FAIL: No 'Final Status' label found in Report Summary.")

    # 5. Manager Notified = N
    entry = find_label(["manager notified", "managernotified"])
    if entry:
        orig_label, val = entry
        val_str = str(val).strip() if val is not None else ""
        if val_str.upper() in ["N", "NO"]:
            checks_passed += 1
            feedback_parts.append(f"PASS: Manager Notified = '{val_str}'")
        else:
            feedback_parts.append(f"FAIL: Manager Notified expected 'N', got '{val_str}'")
    else:
        feedback_parts.append("FAIL: No 'Manager Notified' label found in Report Summary.")

    # 6. Comment(s) = "T&E review complete. All expenses approved."
    entry = find_label(["comment", "comments"])
    if entry:
        orig_label, val = entry
        val_str = str(val).strip() if val is not None else ""
        expected = "T&E review complete. All expenses approved."
        # Flexible comparison: case-insensitive, ignore trailing/leading whitespace
        if val_str.lower() == expected.lower() or expected.lower() in val_str.lower():
            checks_passed += 1
            feedback_parts.append(f"PASS: Comments = '{val_str}'")
        else:
            feedback_parts.append(f"FAIL: Comments expected '{expected}', got '{val_str}'")
    else:
        feedback_parts.append("FAIL: No 'Comment'/'Comments' label found in Report Summary.")

    score = checks_passed / total_checks
    passed = checks_passed == total_checks
    feedback = f"Hiroshi Tanaka Report Summary: {checks_passed}/{total_checks} checks passed.\n" + "\n".join(feedback_parts)

    return {"pass": passed, "score": score, "feedback": feedback}

from pathlib import Path
import re
import datetime

def verify(workspace_path, external_services_path=None):
    import openpyxl

    filepath = Path(workspace_path) / "expense_reports.xlsx"
    if not filepath.exists():
        return {"pass": False, "score": 0.0, "feedback": "File expense_reports.xlsx not found."}

    wb = openpyxl.load_workbook(str(filepath))

    sheet = None
    for name in wb.sheetnames:
        if "carlos" in name.lower() and "mendez" in name.lower():
            sheet = wb[name]
            break
    if sheet is None:
        return {"pass": False, "score": 0.0, "feedback": f"Worksheet 'Carlos Mendez' not found. Available sheets: {wb.sheetnames}"}

    rows_by_key = {}
    for row in sheet.iter_rows(min_row=1, values_only=False):
        cell_a = row[0].value
        if cell_a and isinstance(cell_a, str) and "Mendez" in cell_a and "OPS" in cell_a:
            key = cell_a.strip()
            vals = [c.value for c in row]
            rows_by_key[key] = vals

    def parse_num(v):
        if v is None:
            return 0.0
        if isinstance(v, (int, float)):
            return float(v)
        s = str(v).strip().replace("$", "").replace(",", "").strip()
        if s == "" or s.lower() == "none":
            return 0.0
        try:
            return float(s)
        except ValueError:
            return None

    def nums_close(a, b, tol=0.05):
        if a is None or b is None:
            return False
        if abs(b) < 0.01:
            return abs(a) < 0.01 + tol
        return abs(a - b) <= max(abs(b) * tol, 0.05)

    def normalize_str(s):
        if s is None:
            return ""
        return str(s).strip().lower()

    def parse_date_tuple(val):
        if val is None:
            return None
        if isinstance(val, (datetime.datetime, datetime.date)):
            return (val.month, val.day, val.year)
        s = str(val).strip()
        m = re.match(r'(\d{1,2})/(\d{1,2})/(\d{4})', s)
        if m:
            return (int(m.group(1)), int(m.group(2)), int(m.group(3)))
        m = re.match(r'(\d{4})-(\d{1,2})-(\d{1,2})', s)
        if m:
            return (int(m.group(2)), int(m.group(3)), int(m.group(1)))
        return None

    def date_matches(actual_cell, expected_str):
        exp_lower = expected_str.lower().strip()
        # Range expected
        if ' - ' in exp_lower:
            parts = re.findall(r'(\d{1,2})/(\d{1,2})/(\d{4})', exp_lower)
            if len(parts) >= 2:
                start = (int(parts[0][0]), int(parts[0][1]), int(parts[0][2]))
                end = (int(parts[1][0]), int(parts[1][1]), int(parts[1][2]))
                act_str = normalize_str(actual_cell)
                if all(f"{m}/{d}" in act_str or f"{m:02d}/{d:02d}" in act_str
                       for m, d, _ in (start, end)):
                    return True
                act_tuple = parse_date_tuple(actual_cell)
                if act_tuple in (start, end):
                    return True
                return False
        # Single date expected
        exp_tuple = parse_date_tuple(expected_str)
        act_tuple = parse_date_tuple(actual_cell)
        if exp_tuple and act_tuple and exp_tuple == act_tuple:
            return True
        act_str = normalize_str(actual_cell)
        if exp_lower in act_str or act_str in exp_lower:
            return True
        return False

    def merchant_matches(cell_val, expected):
        if cell_val is None:
            return False
        return normalize_str(cell_val) == normalize_str(expected) or normalize_str(expected) in normalize_str(cell_val)

    def category_matches(cell_val, expected):
        return normalize_str(cell_val) == normalize_str(expected)

    def denial_reason_blank(cell_val):
        v = normalize_str(cell_val)
        return v == "" or v == "none" or v == "n/a" or v == "0"

    def denial_reason_present(cell_val, keywords):
        v = normalize_str(cell_val)
        if v == "" or v == "none":
            return False
        for kw in keywords:
            if kw.lower() not in v:
                return False
        return True

    expected = [
        {"key": "OPS-19", "date": "5/5/2026", "merchant": "Delta", "amount": 384.40, "category": "Staff Expense", "approved": 384.40, "denied": 0, "denial_reason_required": False},
