from pathlib import Path
import re
import openpyxl


def verify(workspace_path, external_services_path=None):
    file_path = Path(workspace_path) / "expense_reports.xlsx"
    if not file_path.exists():
        return {"pass": False, "score": 0.0, "feedback": f"File not found: {file_path}"}

    wb = openpyxl.load_workbook(str(file_path), data_only=True)

    # Find the Carlos Mendez worksheet (case-insensitive, flexible spacing)
    target_ws = None
    for name in wb.sheetnames:
        if re.search(r'carlos\s+mendez', name, re.IGNORECASE):
            target_ws = wb[name]
            break

    if target_ws is None:
        return {"pass": False, "score": 0.0, "feedback": f"No worksheet matching 'Carlos Mendez' found. Sheets: {wb.sheetnames}"}

    # Read all rows into a list of (colA, colB) tuples
    rows = []
    for row in target_ws.iter_rows(min_row=1, max_col=2, values_only=True):
        a_val = row[0] if row[0] is not None else ""
        b_val = row[1] if len(row) > 1 and row[1] is not None else ""
        rows.append((a_val, b_val))

    # Find the Report Summary section
    summary_start = None
    for i, (a, b) in enumerate(rows):
        if isinstance(a, str) and re.search(r'report\s+summary', a, re.IGNORECASE):
            summary_start = i
            break

    if summary_start is None:
        return {"pass": False, "score": 0.0, "feedback": "'Report Summary' header not found in column A."}

    # Build a dict of label -> value from the summary section
    summary = {}
    for a, b in rows[summary_start + 1:]:
        if isinstance(a, str) and a.strip():
            summary[a.strip().lower()] = b

    # Also check starting from summary_start itself in case labels include that row
    a0, b0 = rows[summary_start]
    if isinstance(a0, str) and a0.strip().lower() != 'report summary':
        summary[a0.strip().lower()] = b0

    def clean_num(val):
        """Extract a numeric value from a cell, stripping currency symbols, commas, etc."""
        if val is None:
            return None
        if isinstance(val, (int, float)):
            return float(val)
        s = str(val).replace('$', '').replace(',', '').replace(' ', '').strip()
        try:
            return float(s)
        except ValueError:
            return None

    def find_key(dictionary, *candidates):
        """Find a value in dict by trying multiple key variations (case-insensitive)."""
        for key in dictionary:
            for c in candidates:
                if re.fullmatch(c, key, re.IGNORECASE):
                    return dictionary[key]
        return None

    checks_passed = 0
    total_checks = 6
    feedback_parts = []

    # 1. Jira Key
    jira_val = find_key(summary, r'jira\s*key')
    if jira_val is not None and re.search(r'OPS-32', str(jira_val), re.IGNORECASE):
        checks_passed += 1
        feedback_parts.append(f"PASS Jira Key: found '{jira_val}'")
    else:
        feedback_parts.append(f"FAIL Jira Key: expected 'OPS-32', found '{jira_val}'")

    # 2. Total Approved ~2654.68 ± 1.00
    approved_val = find_key(summary, r'total\s*approved')
    approved_num = clean_num(approved_val)
    if approved_num is not None and abs(approved_num - 2654.68) <= 1.00:
        checks_passed += 1
        feedback_parts.append(f"PASS Total Approved: {approved_num}")
    else:
        feedback_parts.append(f"FAIL Total Approved: expected ~2654.68 (±1.00), found '{approved_val}' (numeric: {approved_num})")

    # 3. Total Denied == 32.00 (use ±1.00 tolerance)
    denied_val = find_key(summary, r'total\s*denied')
    denied_num = clean_num(denied_val)
    if denied_num is not None and abs(denied_num - 32.00) <= 1.00:
        checks_passed += 1
        feedback_parts.append(f"PASS Total Denied: {denied_num}")
    else:
        feedback_parts.append(f"FAIL Total Denied: expected 32.00, found '{denied_val}' (numeric: {denied_num})")

    # 4. Final Status
    status_val = find_key(summary, r'final\s*status')
    if status_val is not None and re.search(r'partially\s*approved', str(status_val), re.IGNORECASE):
        checks_passed += 1
        feedback_parts.append(f"PASS Final Status: '{status_val}'")
    else:
        feedback_parts.append(f"FAIL Final Status: expected 'Partially Approved', found '{status_val}'")

    # 5. Manager Notified
    notified_val = find_key(summary, r'manager\s*notified')
    if notified_val is not None and str(notified_val).strip().upper() == 'N':
        checks_passed += 1
        feedback_parts.append(f"PASS Manager Notified: '{notified_val}'")
    else:
        feedback_parts.append(f"FAIL Manager Notified: expected 'N', found '{notified_val}'")

    # 6. Comments
    comment_val = find_key(summary, r'comments?')
    expected_comment = "T&E review complete. Expenses approved except where noted."
    if comment_val is not None:
        # Loose comparison: strip, case-insensitive, allow minor punctuation differences
        c_clean = re.sub(r'\s+', ' ', str(comment_val).strip().lower())
        e_clean = re.sub(r'\s+', ' ', expected_comment.strip().lower())
        if c_clean == e_clean or e_clean in c_clean:
            checks_passed += 1
            feedback_parts.append(f"PASS Comment: '{comment_val}'")
        else:
            feedback_parts.append(f"FAIL Comment: expected '{expected_comment}', found '{comment_val}'")
    else:
        feedback_parts.append(f"FAIL Comment: label 'Comment'/'Comments' not found in summary section")

    score = checks_passed / total_checks
    passed = checks_passed == total_checks
    feedback = f"Carlos Mendez Report Summary: {checks_passed}/{total_checks} checks passed.\n" + "\n".join(feedback_parts)
    return {"pass": passed, "score": score, "feedback": feedback}

from pathlib import Path
import openpyxl
import re
import datetime

def verify(workspace_path, external_services_path=None):
    filepath = Path(workspace_path) / "expense_reports.xlsx"
    if not filepath.exists():
        return {"pass": False, "score": 0.0, "feedback": "File expense_reports.xlsx not found."}

    wb = openpyxl.load_workbook(str(filepath))
    sheet = None
    for name in wb.sheetnames:
        if "priya" in name.lower() and "natarajan" in name.lower():
            sheet = wb[name]
            break
    if sheet is None:
        return {"pass": False, "score": 0.0, "feedback": f"Worksheet 'Priya Natarajan' not found. Available sheets: {wb.sheetnames}"}

    rows = []
    for row in sheet.iter_rows(min_row=1, values_only=False):
        vals = [cell.value for cell in row]
        rows.append(vals)

    row_dict = {}
    for r in rows:
        key = str(r[0]).strip() if r[0] is not None else ""
        if key:
            row_dict[key] = r

    def parse_num(val):
        if val is None:
            return None
        if isinstance(val, (int, float)):
            return float(val)
        s = str(val).strip()
        s = re.sub(r'[\$,]', '', s)
        try:
            return float(s)
        except:
            return None

    def normalize_str(val):
        if val is None:
            return ""
        return str(val).strip().lower()

    def parse_date_tuple(val):
        if val is None:
            return None
        if isinstance(val, (datetime.datetime, datetime.date)):
            return (val.month, val.day, val.year)
        s = str(val).strip()
        m = re.match(r'(\d{1,2})/(\d{1,2})/(\d{4})', s)
        if m:
            return (int(m.group(1)), int(m.group(2)), int(m.group(3)))
        m = re.match(r'(\d{4})-(\d{1,2})-(\d{1,2})', s)
        if m:
            return (int(m.group(2)), int(m.group(3)), int(m.group(1)))
        return None

    def date_matches(actual_cell, expected_str):
        exp_lower = expected_str.lower().strip()
        if ' - ' in exp_lower or ' to ' in exp_lower:
            parts = re.findall(r'(\d{1,2})/(\d{1,2})/(\d{4})', exp_lower)
            if len(parts) >= 2:
                start = (int(parts[0][0]), int(parts[0][1]), int(parts[0][2]))
                end = (int(parts[1][0]), int(parts[1][1]), int(parts[1][2]))
                act_str = normalize_str(actual_cell)
                # Accept a textual span mentioning both dates (slash or ISO form)
                start_iso = f"{start[2]}-{start[0]:02d}-{start[1]:02d}"
                end_iso = f"{end[2]}-{end[0]:02d}-{end[1]:02d}"
                if (start_iso in act_str and end_iso in act_str):
                    return True
                if all(f"{m}/{d}" in act_str or f"{m:02d}/{d:02d}" in act_str
                       for m, d, _ in (start, end)):
                    return True
                act_tuple = parse_date_tuple(actual_cell)
                if act_tuple in (start, end):
                    return True
                return False
        exp_tuple = parse_date_tuple(expected_str)
        act_tuple = parse_date_tuple(actual_cell)
        if exp_tuple and act_tuple and exp_tuple == act_tuple:
            return True
        act_str = normalize_str(actual_cell)
        if exp_lower in act_str or act_str in exp_lower:
            return True
        return False

    def merchant_matches(cell_val, expected):
        if cell_val is None:
            return False
        return normalize_str(cell_val) == normalize_str(expected) or normalize_str(expected) in normalize_str(cell_val) or normalize_str(cell_val) in normalize_str(expected)

    def category_matches(cell_val, expected):
        if cell_val is None:
            return False
        return normalize_str(expected) in normalize_str(cell_val) or normalize_str(cell_val) in normalize_str(expected)

    def denial_reason_ok(cell_val):
        if cell_val is None:
            return False
        s = normalize_str(cell_val)
        if "business justification" in s or ("justification" in s and ("missing" in s or "no " in s)):
            return True
        if "personal" in s and ("expense" in s or "reimbursement" in s or "claim" in s):
            return True
        return False

    expected_rows = [
        {
            "key": "OPS-34",
            "date": "5/5/2026",
            "merchant": "Self drove (mileage)",
            "amount_check": lambda v: ("200" in str(v) and ("mile" in str(v).lower() or "mi" in str(v).lower())) or (parse_num(v) == 200 if v is not None else False),
            "amount_display": "200 miles or equivalent",
            "category": "Staff Expense",
            "approved": 0,
            "denied": 145.00,
            "denied_tol": 0.10
        },
        {
            "key": "OPS-33",
            "date": "5/5/2026",
            "merchant": "Riverfront Deli",
            "amount_check": lambda v: abs((parse_num(v) or -999) - 16.59) < 0.05,
            "amount_display": "16.59",
            "category": "Staff Expense",
            "approved": 0,
            "denied": 16.59,
            "denied_tol": 0.05
        },
        {
            "key": "OPS-35",
            "date": "5/6/2026",
            "merchant": "The Creamery Cafe",
            "amount_check": lambda v: abs((parse_num(v) or -999) - 21.40) < 0.05,
            "amount_display": "21.40",
            "category": "Staff Expense",
            "approved": 0,
            "denied": 21.40,
            "denied_tol": 0.05
        },
        {
            "key": "OPS-36",
            "date": "5/7/2026",
            "merchant": "Canal Street Kitchen",
            "amount_check": lambda v: abs((parse_num(v) or -999) - 16.05) < 0.05,
            "amount_display": "16.05",
            "category": "Staff Expense",
            "approved": 0,
            "denied": 16.05,
            "denied_tol": 0.05
        },
        {
            "key": "OPS-37",
            "date": "5/8/2026",
            "merchant": "The Landing Spot",
            "amount_check": lambda v: abs((parse_num(v) or -999) - 20.33) < 0.05,
            "amount_display": "20.33",
            "category": "Staff Expense",
            "approved": 0,
            "denied": 20.33,
            "denied_tol": 0.05
        },
        {
            "key": "OPS-38",
            "date": "5/5/2026 - 5/9/2026",
            "merchant": "Serenity Hotel and Spa",
            "amount_check": lambda v: abs((parse_num(v) or -999) - 1471.96) < 1.0,
            "amount_display": "1471.96",
            "category": "Staff Expense",
            "approved": 0,
            "denied": 1471.96,
            "denied_tol": 1.0
        }
    ]

    issues = []
    passed_count = 0
    total_checks = len(expected_rows)

    for exp in expected_rows:
        jira_key = exp["key"]
        found_row = None
        for rk, rv in row_dict.items():
            if jira_key.lower() in rk.lower() or rk.lower() in jira_key.lower():
                found_row = rv
                break

        if found_row is None:
            issues.append(f"Row with Jira Key '{jira_key}' not found.")
            continue

        row_issues = []

        date_val = found_row[1] if len(found_row) > 1 else None
        if not date_matches(date_val, exp["date"]):
            row_issues.append(f"Date: expected '{exp['date']}', got '{date_val}'")

        merchant_val = found_row[2] if len(found_row) > 2 else None
        if not merchant_matches(merchant_val, exp["merchant"]):
            merchant_s = normalize_str(merchant_val)
            exp_words = [w.lower() for w in exp["merchant"].split() if len(w) > 2]
            matching_words = sum(1 for w in exp_words if w in merchant_s)
            if matching_words < len(exp_words) * 0.5:
                row_issues.append(f"Merchant: expected '{exp['merchant']}', got '{merchant_val}'")

        amount_val = found_row[3] if len(found_row) > 3 else None
        if not exp["amount_check"](amount_val):
            row_issues.append(f"Amount: expected {exp['amount_display']}, got '{amount_val}'")

        cat_val = found_row[4] if len(found_row) > 4 else None
        if not category_matches(cat_val, exp["category"]):
            row_issues.append(f"Category: expected '{exp['category']}', got '{cat_val}'")

        approved_val = parse_num(found_row[5]) if len(found_row) > 5 else None
        if approved_val is None or abs(approved_val - exp["approved"]) > 0.05:
            row_issues.append(f"Approved Amount: expected {exp['approved']}, got '{found_row[5] if len(found_row) > 5 else None}'")

        denied_val = parse_num(found_row[6]) if len(found_row) > 6 else None
        if denied_val is None or abs(denied_val - exp["denied"]) > exp["denied_tol"]:
            row_issues.append(f"Denied Amount: expected {exp['denied']} (±{exp['denied_tol']}), got '{found_row[6] if len(found_row) > 6 else None}'")

        reason_val = found_row[7] if len(found_row) > 7 else None
        if not denial_reason_ok(reason_val):
            row_issues.append(f"Denial Reason: expected equivalent to 'Missing business justification. Please submit personal reimbursement.', got '{reason_val}'")

        if row_issues:
            issues.append(f"Row '{jira_key}': " + "; ".join(row_issues))
        else:
            passed_count += 1

    score = passed_count / total_checks if total_checks > 0 else 0.0
    passed = passed_count == total_checks

    if passed:
        feedback = f"All {total_checks} line-item rows in 'Priya Natarajan' worksheet verified successfully."
    else:
        feedback = f"{passed_count}/{total_checks} rows passed. Issues:\n" + "\n".join(issues)

    return {"pass": passed, "score": score, "feedback": feedback}

