        feedback_parts.append(f"PASS Final Status: '{fs_val}'")
    else:
        feedback_parts.append(f"FAIL Final Status: expected 'Denied', found '{fs_val}'")

    # 5. Manager Notified == Y
    mn_val = get_val(["Manager Notified"])
    if mn_val is not None and str(mn_val).strip().upper().startswith("Y"):
        checks_passed += 1
        feedback_parts.append(f"PASS Manager Notified: '{mn_val}'")
    else:
        feedback_parts.append(f"FAIL Manager Notified: expected 'Y', found '{mn_val}'")

    # 6. Comment / Comments — must mention denied and cite amount ~1691.33
    cm_val = get_val(["Comment", "Comments"])
    cm_pass = False
    if cm_val is not None:
        cm_str = str(cm_val).lower()
        if "denied" in cm_str or "deny" in cm_str or "denial" in cm_str:
            # Look for a number near 1691.33
            nums = re.findall(r'\d[\d,]*\.?\d*', cm_str)
            for n in nums:
                try:
                    nf = float(n.replace(',', ''))
                    if abs(nf - 1691.33) <= 1.00:
                        cm_pass = True
                        break
                except ValueError:
                    pass
    if cm_pass:
        checks_passed += 1
        feedback_parts.append(f"PASS Comment: '{cm_val}'")
    else:
        feedback_parts.append(f"FAIL Comment: expected text stating denial with amount ~1691.33, found '{cm_val}'")

    score = checks_passed / total_checks
    passed = checks_passed == total_checks
    feedback = f"{checks_passed}/{total_checks} checks passed. " + "; ".join(feedback_parts)
    return {"pass": passed, "score": score, "feedback": feedback}

from pathlib import Path
import json
import re

def verify(workspace_path, external_services_path=None):
    # We need to check slack_data.json for any messages in #finance-approvals
    # referencing Rahimi's expense report. Per SOP 6.2 Step 9, no manager
    # notification is required since denials are under $200.

    slack_path = None

    # Check external_services_path first
    if external_services_path:
        candidate = Path(external_services_path) / "slack_data.json"
        if candidate.exists():
            slack_path = candidate

    # Also check workspace_path
    if slack_path is None:
        candidate = Path(workspace_path) / "slack_data.json"
        if candidate.exists():
            slack_path = candidate

    # Search more broadly if not found
    if slack_path is None:
        for p in Path(workspace_path).rglob("slack_data.json"):
            slack_path = p
            break
        if slack_path is None and external_services_path:
            for p in Path(external_services_path).rglob("slack_data.json"):
                slack_path = p
                break

    if slack_path is None:
        return {
            "pass": True,
            "score": 1.0,
            "feedback": "No slack_data.json found anywhere. Since no Slack messages exist, no manager notification about Rahimi was sent. PASS."
        }

    try:
        with open(slack_path, 'r') as f:
            slack_data = json.load(f)
    except Exception as e:
        return {"pass": False, "score": 0.0, "feedback": f"Could not read slack_data.json: {e}"}

    # Find the #finance-approvals channel ID
    channels = slack_data.get("channels", {})
    finance_approvals_ids = []
    for ch_id, ch_info in channels.items():
        ch_name = ""
        if isinstance(ch_info, dict):
            ch_name = ch_info.get("name", "")
        elif isinstance(ch_info, str):
            ch_name = ch_info
        if ch_name.lower().replace("#", "") == "finance-approvals":
            finance_approvals_ids.append(ch_id)

    # If no finance-approvals channel found, check all channels as a fallback
    # (be generous - maybe the channel name is slightly different)
    if not finance_approvals_ids:
        for ch_id, ch_info in channels.items():
            ch_name = ""
            if isinstance(ch_info, dict):
                ch_name = ch_info.get("name", "")
            elif isinstance(ch_info, str):
                ch_name = ch_info
            if "finance" in ch_name.lower() and "approv" in ch_name.lower():
                finance_approvals_ids.append(ch_id)

    messages_data = slack_data.get("messages", {})

    # Collect messages from the finance-approvals channel(s)
    flagged_messages = []

    rahimi_patterns = [
        r'OPS-HR-TE-Rahimi',
        r'Rahimi',
        r'Leila\s+Rahimi',
    ]

    def check_text(text, source_desc):
        if not isinstance(text, str):
            return
        for pattern in rahimi_patterns:
            if re.search(pattern, text, re.IGNORECASE):
                flagged_messages.append(f"Found '{pattern}' match in {source_desc}: {text[:300]}")
                break  # one match per text is enough

    def search_messages(msg_list, channel_desc):
        if not isinstance(msg_list, list):
            return
        for i, msg in enumerate(msg_list):
            if isinstance(msg, dict):
                text = msg.get("text", "")
                check_text(text, f"{channel_desc} message[{i}]")
                # Also check attachments or blocks
                for key in ["attachments", "blocks"]:
                    val = msg.get(key, [])
                    if isinstance(val, list):
                        for j, item in enumerate(val):
                            if isinstance(item, dict):
                                for field in ["text", "fallback", "pretext", "title"]:
                                    check_text(item.get(field, ""), f"{channel_desc} message[{i}].{key}[{j}].{field}")
            elif isinstance(msg, str):
                check_text(msg, f"{channel_desc} message[{i}]")

    if finance_approvals_ids:
        for ch_id in finance_approvals_ids:
            msg_list = messages_data.get(ch_id, [])
            search_messages(msg_list, f"#finance-approvals ({ch_id})")
    else:
        # No finance-approvals channel found; check all channels as a broader search
        for ch_id, msg_list in messages_data.items():
            search_messages(msg_list, f"channel {ch_id}")

    if flagged_messages:
        details = "\n".join(flagged_messages)
        return {
            "pass": False,
            "score": 0.0,
            "feedback": f"FAIL: Found Slack messages in #finance-approvals (or relevant channels) referencing Rahimi's expense report. Per SOP 6.2 Step 9, no manager notification should have been sent since denials are under $200.\nDetails:\n{details}"
        }

    return {
        "pass": True,
        "score": 1.0,
        "feedback": "PASS: No Slack messages found in #finance-approvals referencing Rahimi or her expense report (OPS-HR-TE-Rahimi). No manager notification was sent, which is correct per SOP 6.2 Step 9 since denials are under $200."
    }

import json
import os
import re
import datetime

def verify(workspace_path, external_services_path=None):
    # --- Locate slack_data.json, preferring post-run state --------------
    preferred_subpaths = [
        "external_services_final/slack_data.json",
        "external_services/slack_data.json",
        "workspace/slack_data.json",
        "draft/external_services_final/slack_data.json",
        "draft/workspace/slack_data.json",
        "draft/slack_data.json",
        "slack_data.json",
    ]
    candidates = [os.path.join(workspace_path, p) for p in preferred_subpaths]
    parent = os.path.dirname(workspace_path.rstrip("/"))
    if parent:
        candidates.extend(os.path.join(parent, p) for p in preferred_subpaths)

    slack_path = next((c for c in candidates if os.path.isfile(c)), None)

    # Recursive fallback — but skip _initial, prefer _final, then anything else
    if slack_path is None:
        hits = []
        roots = [workspace_path] + ([parent] if parent else [])
        for root in roots:
            if not os.path.isdir(root):
                continue
            for dirpath, _, filenames in os.walk(root):
                if "slack_data.json" in filenames:
                    hits.append(os.path.join(dirpath, "slack_data.json"))

        def _rank(p):
            lp = p.lower()
            if "_initial" in lp or "initial" in os.path.basename(os.path.dirname(lp)):
                return 3
            if "_final" in lp or "final" in os.path.basename(os.path.dirname(lp)):
                return 0
            if "workspace" in lp:
                return 1
            return 2

        hits.sort(key=_rank)
        if hits:
            slack_path = hits[0]

    if slack_path is None:
        return {"pass": False, "score": 0.0,
                "feedback": f"Could not locate slack_data.json under {workspace_path}"}

    try:
        with open(slack_path, "r") as f:
            slack_data = json.load(f)
    except Exception as e:
        return {"pass": False, "score": 0.0,
                "feedback": f"Could not load slack_data.json at {slack_path}: {e}"}

    # --- Figure out which channel IDs correspond to #finance-approvals ---
    target_ch_ids = {"C001"}

    def _register_channel(ch_id, ch_name):
        if ch_id:
            if ch_id == "C001":
                target_ch_ids.add(ch_id)
            if ch_name and "finance-approvals" in ch_name.lower().replace("#", ""):
                target_ch_ids.add(ch_id)

    channels_field = slack_data.get("channels") if isinstance(slack_data, dict) else None
    if isinstance(channels_field, dict):
        for ch_id, ch in channels_field.items():
            ch_name = ch.get("name", "") if isinstance(ch, dict) else ""
            _register_channel(ch_id, ch_name)
    elif isinstance(channels_field, list):
        for ch in channels_field:
            if isinstance(ch, dict):
                _register_channel(ch.get("id") or ch.get("channel_id"),
                                   ch.get("name", ""))

    # --- Collect messages from every plausible shape --------------------
    def _msg_in_target_channel(m):
        if not isinstance(m, dict):
            return False
        ch = (m.get("channel_id") or m.get("channel")
              or m.get("channel_name") or m.get("conversation_id"))
        if ch is None:
            return False
        if ch in target_ch_ids:
            return True
        if isinstance(ch, str) and "finance-approvals" in ch.lower().replace("#", ""):
            return True
        return False

    messages = []

    msgs_field = slack_data.get("messages") if isinstance(slack_data, dict) else None
    if isinstance(msgs_field, dict):
        for ch_id, ms in msgs_field.items():
            if ch_id in target_ch_ids and isinstance(ms, list):
                messages.extend(ms)
            elif isinstance(ch_id, str) and "finance-approvals" in ch_id.lower().replace("#", ""):
                if isinstance(ms, list):
                    messages.extend(ms)
    elif isinstance(msgs_field, list):
        for m in msgs_field:
            if _msg_in_target_channel(m):
                messages.append(m)

    if isinstance(channels_field, dict):
        for ch_id, ch in channels_field.items():
            if not isinstance(ch, dict):
                continue
            if ch_id not in target_ch_ids and \
               "finance-approvals" not in str(ch.get("name", "")).lower().replace("#", ""):
                continue
            for key in ("messages", "msgs", "posts", "history"):
                nested = ch.get(key)
                if isinstance(nested, list):
                    messages.extend(nested)
    elif isinstance(channels_field, list):
        for ch in channels_field:
            if not isinstance(ch, dict):
                continue
            ch_id = ch.get("id") or ch.get("channel_id")
            ch_name = ch.get("name", "")
            if ch_id not in target_ch_ids and \
               "finance-approvals" not in str(ch_name).lower().replace("#", ""):
                continue
            for key in ("messages", "msgs", "posts", "history"):
                nested = ch.get(key)
                if isinstance(nested, list):
                    messages.extend(nested)

    if not messages:
        found = []

        def _walk(obj):
            if isinstance(obj, dict):
                text = obj.get("text") or obj.get("message") or obj.get("body")
                if isinstance(text, str) and text.strip():
                    if _msg_in_target_channel(obj):
                        found.append(obj)
                    elif "t&e review flag" in text.lower() and "natarajan" in text.lower():
                        found.append(obj)
                for v in obj.values():
                    _walk(v)
            elif isinstance(obj, list):
                for v in obj:
                    _walk(v)

        _walk(slack_data)
        messages.extend(found)

    if not messages:
        return {
            "pass": False, "score": 0.0,
            "feedback": (
                f"No messages found in finance-approvals channel. "
                f"Loaded slack_data.json from {slack_path}. "
                f"Target channel IDs: {sorted(target_ch_ids)}. "
                f"Top-level keys: {list(slack_data.keys()) if isinstance(slack_data, dict) else type(slack_data).__name__}"
            ),
        }

    # --- Scoring ---------------------------------------------------------
    def score_message(text):
        results = []
        t = text.lower()

        results.append(("T&E Review Flag",
                        "t&e review flag" in t or "t & e review flag" in t))

        results.append(("Priya Natarajan",
                        "priya natarajan" in t or "natarajan" in t))

        results.append(("manager 'l_zahra'",
                        "l_zahra" in t or "@l_zahra" in t))

        start_patterns = [r"5/5/2026", r"05/05/2026", r"2026-05-05"]
        end_patterns = [
            r"5/9/2026", r"05/09/2026", r"2026-05-09",
            r"5/10/2026", r"05/10/2026", r"2026-05-10",
        ]
        start_ok = any(re.search(p, t) for p in start_patterns)
        end_ok = any(re.search(p, t) for p in end_patterns)
        results.append((
            "Date range covers 5/5/2026 through 5/9 or 5/10/2026",
            start_ok and end_ok,
        ))

        approved_match = re.search(
            r"(?:total\s+(?:amount\s+)?approved|amount\s+approved)[^\d\-]*\$?\s*([\d,]+\.?\d*)",
            t)
        approved_ok = False
        approved_val = None
        if approved_match:
            try:
                approved_val = float(approved_match.group(1).replace(",", ""))
                approved_ok = abs(approved_val - 0.0) < 1.0
            except Exception:
                approved_ok = False
        results.append((f"Total Amount Approved = 0 (got {approved_val})",
                        approved_ok))

        denied_match = re.search(
            r"(?:total\s+(?:amount\s+)?denied|amount\s+denied)[^\d\-]*\$?\s*([\d,]+\.?\d*)",
            t)
        denied_ok = False
        denied_val = None
        if denied_match:
            try:
                denied_val = float(denied_match.group(1).replace(",", ""))
                denied_ok = abs(denied_val - 1691.33) < 1.0
            except Exception:
                denied_ok = False
        results.append((
            f"Total Amount Denied within $1.00 of 1691.33 (got {denied_val})",
            denied_ok,
        ))

        results.append(("Includes mileage line",
                        "mileage" in t))

        biz = ("business justification" in t or "business purpose" in t
               or "calendar" in t or "no calendar" in t)
        action = ("action taken" in t and ("denied" in t or "denial" in t))
        results.append((
            "Business justification + Action Taken (denial) present",
            biz and action,
        ))

        passes = sum(1 for _, ok in results if ok)
        return passes, results

    best = (0, [], None)
    for msg in messages:
        text = msg.get("text") if isinstance(msg, dict) else str(msg)
        if not text:
            text = msg.get("message") if isinstance(msg, dict) else ""
        if not text:
            continue
        passes, results = score_message(text)
        if passes > best[0]:
            best = (passes, results, text)

    total_checks = 8
    score = best[0] / total_checks
    feedback_lines = [
        f"Loaded slack_data.json from {slack_path}",
        f"Best matching message scored {best[0]}/{total_checks}:",
    ]
    for label, ok in best[1]:
        feedback_lines.append(f"{'PASS' if ok else 'FAIL'}: {label}")
    return {
        "pass": best[0] == total_checks,
        "score": score,
        "feedback": "\n".join(feedback_lines),
    }

from pathlib import Path
import json
import re

def verify(workspace_path, external_services_path=None):
    # We need to check slack_data.json for any messages in #finance-approvals
    # referencing Mendez's expense report to a manager.
    # Per SOP 6.2 Step 9, no manager notification is required since denials are under $200.

    slack_path = None
    candidates = []
    if external_services_path:
        candidates.append(Path(external_services_path) / "slack_data.json")
        candidates.append(Path(external_services_path) / "slack" / "slack_data.json")
    candidates.append(Path(workspace_path) / "slack_data.json")

    for c in candidates:
        if c.exists():
            slack_path = c
            break

    if slack_path is None:
        # No slack_data.json found; no messages were sent, so no manager notification for Mendez exists.
        return {"pass": True, "score": 1.0, "feedback": "No slack_data.json found; no Slack messages were sent, so no manager notification for Mendez exists. PASS."}

    try:
        with open(slack_path, 'r') as f:
            slack_data = json.load(f)
    except Exception as e:
        return {"pass": True, "score": 1.0, "feedback": f"Could not parse slack_data.json ({e}); assuming no problematic messages. PASS (lenient)."}

    # Find the channel ID for #finance-approvals
    finance_channel_id = None
    channels = slack_data.get("channels", {})
    if isinstance(channels, dict):
        for cid, cinfo in channels.items():
            if isinstance(cinfo, dict):
                cname = cinfo.get("name", "")
                if cname.lower() == "finance-approvals":
                    finance_channel_id = cid
                    break

    # Collect messages from #finance-approvals channel
    finance_messages = []
    messages_data = slack_data.get("messages", {})

    if finance_channel_id and isinstance(messages_data, dict):
        channel_msgs = messages_data.get(finance_channel_id, [])
        if isinstance(channel_msgs, list):
            finance_messages.extend(channel_msgs)

    # Also do a broader search across all channels in case channel naming varies
    all_channel_messages = []
    if isinstance(messages_data, dict):
        for chan_id, msgs in messages_data.items():
            if isinstance(msgs, list):
                for msg in msgs:
                    all_channel_messages.append((chan_id, msg))

    # Helper to extract all text from a message object
    def get_message_text(msg):
        texts = []
        if isinstance(msg, dict):
            if "text" in msg:
                texts.append(str(msg["text"]))
            # Check attachments, blocks, etc.
            for key in ["attachments", "blocks"]:
                if key in msg:
                    items = msg[key]
                    if isinstance(items, list):
                        for item in items:
                            if isinstance(item, dict):
                                for subkey in ["text", "fallback", "pretext", "title"]:
                                    if subkey in item:
                                        texts.append(str(item[subkey]))
        elif isinstance(msg, str):
            texts.append(msg)
        return " ".join(texts)

    # Check 1: Look for messages in #finance-approvals containing "OPS-HR-TE-Mendez" or referencing Mendez + Rahimi
    mendez_jira_pattern = re.compile(r'OPS[-\s]?HR[-\s]?TE[-\s]?Mendez', re.IGNORECASE)
    flagged_texts = []

    # Check finance-approvals channel specifically
    for msg in finance_messages:
        text = get_message_text(msg)
        text_lower = text.lower()
        # Check for Mendez Jira key
        if mendez_jira_pattern.search(text):
            flagged_texts.append(text)
        # Check for Mendez mentioned alongside Rahimi (manager notification)
        elif 'mendez' in text_lower and 'rahimi' in text_lower:
            flagged_texts.append(text)

    if flagged_texts:
        return {
            "pass": False,
            "score": 0.0,
            "feedback": f"FAIL: Found {len(flagged_texts)} Slack message(s) in #finance-approvals containing 'OPS-HR-TE-Mendez' or referencing Mendez's expense report to manager Rahimi. Per SOP 6.2 Step 9, no manager notification should be sent since denials are under $200. Flagged messages: {flagged_texts[:3]}"
        }

    # Check 2: Broader check across all channels for Mendez manager notifications
    mendez_manager_notifications = []
    for chan_id, msg in all_channel_messages:
        text = get_message_text(msg)
        text_lower = text.lower()
        # Check for OPS-HR-TE-Mendez jira key combined with Rahimi or manager-like context
        if mendez_jira_pattern.search(text) and ('rahimi' in text_lower or 'manager' in text_lower or 'notify' in text_lower or 'notification' in text_lower or 'escalat' in text_lower):
            mendez_manager_notifications.append(text)
        # Check for Mendez + Rahimi together suggesting a manager notification
        elif 'mendez' in text_lower and 'rahimi' in text_lower and ('denied' in text_lower or 'denial' in text_lower or 'expense' in text_lower or 'report' in text_lower or 'review' in text_lower or 'notify' in text_lower or 'notification' in text_lower):
            mendez_manager_notifications.append(text)

    if mendez_manager_notifications:
        return {
            "pass": False,
            "score": 0.0,
            "feedback": f"FAIL: Found Slack message(s) that appear to flag Carlos Mendez's expense report to manager Rahimi. Per SOP 6.2 Step 9, no notification is required since denials are under $200. Messages: {mendez_manager_notifications[:3]}"
        }

    return {
        "pass": True,
        "score": 1.0,
        "feedback": "PASS: No Slack messages found in #finance-approvals containing 'OPS-HR-TE-Mendez' or flagging Mendez's expense report to manager Rahimi. This is correct per SOP 6.2 Step 9 since denials are under $200."
    }
